const body = $json.body ?? $json;

const commandText = (body.text ?? "").toString().trim();
const slackUserId = (body.user_id ?? "").toString();
const channelId = (body.channel_id ?? "").toString();
const responseUrl = (body.response_url ?? "").toString();

const command = (body.command ?? "").toString();   
const teamId = (body.team_id ?? "").toString();
const teamDomain = (body.team_domain ?? "").toString();
const channelName = (body.channel_name ?? "").toString();
const userName = (body.user_name ?? "").toString();
const triggerId = (body.trigger_id ?? "").toString(); 
const apiAppId = (body.api_app_id ?? "").toString();


const [verbRaw, ...rest] = commandText.split(/\s+/);
const verb = (verbRaw ?? "").toLowerCase();
const args = rest.join(" ").trim();

return [
  {
    json: {
      commandText,
      slackUserId,
      channelId,
      responseUrl,
      command,
      verb,
      args,
      triggerId,
      teamId,
      teamDomain,
      channelName,
      userName,
      apiAppId,
      raw: body,
    },
  },
];

const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { message: "No active mappings found." } }];
}

const rows = items.map(i => i.json);

// Slack context comes from the AI path node, not the DB rows
let channelId = null;
let slackUserId = null;
let responseUrl = null;
let aiPrompt = null;

try {
  channelId = $node["ai: build mappings filter"].json.channelId;
  slackUserId = $node["ai: build mappings filter"].json.slackUserId;
  responseUrl = $node["ai: build mappings filter"].json.responseUrl;
  aiPrompt = $node["ai: build mappings filter"].json.aiPrompt;
} catch(e) {}

// Fallback to slash command path
try {
  if (!channelId) channelId = $node["compute typeFilter"].json.channelId;
  if (!slackUserId) slackUserId = $node["compute typeFilter"].json.slackUserId;
  if (!responseUrl) responseUrl = $node["compute typeFilter"].json.responseUrl;
  if (!aiPrompt) aiPrompt = $node["compute typeFilter"].json.aiPrompt;
} catch(e) {}

const header = `${"ID".padEnd(5)}${"TYPE".padEnd(14)}${"VALUE RANGE".padEnd(18)}${"PULSES".padEnd(12)}${"INTENSITY".padEnd(14)}${"ACTIVE"}`;
const divider = "-".repeat(75);

const lines = rows.slice(0, 20).map(r => {
  const range   = `${String(r.minvalue ?? "-∞").padEnd(6)}→ ${String(r.maxvalue ?? "+∞")}`;
  const pulses  = `${r.minpulses ?? "?"}-${r.maxpulses ?? "?"}`;
  const intens  = `${r.minintensity ?? "?"}-${r.maxintensity ?? "?"}`;

  return `${String(r.id).padEnd(5)}${String(r.type).padEnd(14)}${range.padEnd(18)}${pulses.padEnd(12)}${intens.padEnd(14)}${r.active}`;
});

const table = [header, divider, ...lines].join("\n");

return [{
  json: {
    responseUrl,
    channelId,
    slackUserId,
    aiPrompt,
    message: table,
    count: rows.length,
  },
}];

