parameters.jsCode:
const heartRate = $node["Data Cleaning1"].json.heartRate;

const userID = $node["Webhook heart rate"].json.body.UserID;
const SmartWatchID = $node["Webhook heart rate"].json.body.SmartWatchID;
const AndroidID = $node["Webhook heart rate"].json.body.AndroidID;

const mappings = items.map(i => i.json);

function map(value, inMin, inMax, outMin, outMax) {
  if (inMin === inMax) return outMin;
  return outMin + (value - inMin) * (outMax - outMin) / (inMax - inMin);
}

let feedback = {
  intensity: 0,
  pulses: 0,
  duration: 0,
  interval: 0,
  alertGiven: "no",
  fbRangeID: null,
  monitoringType: "HeartRate",
  userID,
  SmartWatchID,
  AndroidID,
};

if (!mappings || mappings.length === 0) {
  return [{ json: feedback }];
}

for (const m of mappings) {
  const minHR = parseFloat(m.minvalue);
  const maxHR = parseFloat(m.maxvalue);

  if (heartRate >= minHR && heartRate <= maxHR) {
    feedback.intensity = Math.round(
      map(heartRate, minHR, maxHR, Number(m.minintensity), Number(m.maxintensity))
    );
    feedback.pulses = 10;

    feedback.duration = Math.round(
      map(heartRate, minHR, maxHR, Number(m.minduration), Number(m.maxduration))
    );

    const totalCycleTimeMs = 60000 / heartRate;
    feedback.interval = Math.max(0, Math.round(totalCycleTimeMs - feedback.duration));

    feedback.fbRangeID = parseInt(m.id);
    feedback.alertGiven = feedback.pulses > 0 ? "yes" : "no";
    break;
  }
}

return [{ json: feedback }];

// Extract database readings
// These are ordered by time DESC (Index 0 is the most recent DB entry)
const readings = items.map(item => parseFloat(item.json.value)).filter(v => !isNaN(v));

// Extract raw sensor input from Webhook
const rawValue = parseFloat($('Webhook heart rate').item.json.body.Value || 0);

// Outlier definition
const isOutlier = (v) => v < 40 || v > 220;

// Add raw value if it's valid (for logic consistency)
if (!isOutlier(rawValue)) {
    readings.push(rawValue); 
}

// LOWER the alpha to make smoothing stronger against vibration noise
// 0.1 means "Trust the history 90%, trust the new value 10%"
const alpha = 0.1; 

let smoothed = rawValue; // Default if no history

if (readings.length > 0) {
    // FIX: Use readings[0] because your SQL sorts by DESC (Newest First)
    // This gets the most recent saved value from the database
    const prev = readings[0]; 
    smoothed = alpha * rawValue + (1 - alpha) * prev;
}

return [
  {
    json: {
      heartRate: Math.round(smoothed),
      rawValue: rawValue
    }
  }
];

const rows = items.map(i => i.json);

if (!rows || rows.length === 0) {
  return [{ json: { statusCode: 404, payload: [] } }];
}

return [{ json: { statusCode: 200, payload: rows } }];

const q = $input.first().json.query || {};
const range = q.range || "All Time";
const alertTypeRaw = q.alert_type;
const userIdRaw = q.userid;
const startDateRaw = q.start_date;
const endDateRaw = q.end_date;

if (!userIdRaw) {
  return [{ json: { statusCode: 400, payload: { error: "Missing required userid parameter" } } }];
}
if (alertTypeRaw === undefined || alertTypeRaw === null || String(alertTypeRaw).trim() === "") {
  return [{ json: { statusCode: 400, payload: { error: "Missing required alert_type parameter" } } }];
}

const userId = Number(userIdRaw);
if (!Number.isFinite(userId)) {
  return [{ json: { statusCode: 400, payload: { error: "userid must be a number" } } }];
}

const alertTypeStr = String(alertTypeRaw).trim();
const isNumericAlertType = /^[0-9]+$/.test(alertTypeStr);

const now = new Date();
let dateFrom = null;
let dateTo = null;

switch (range) {
  case "Last 24 Hours":
  case "Last+24+Hours":
    dateFrom = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    break;
  case "Last 7 Days":
  case "Last+7+Days":
    dateFrom = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    break;
  case "Last 30 Days":
  case "Last+30+Days":
    dateFrom = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
    break;
  case "custom":
  case "Custom Date Range":
  case "Custom+Date+Range":
    // Parse custom date range
    if (startDateRaw) {
      dateFrom = new Date(startDateRaw + "T00:00:00");
    }
    if (endDateRaw) {
      // Set to end of day (23:59:59)
      dateTo = new Date(endDateRaw + "T23:59:59");
    }
    break;
  default:
    dateFrom = null;
    dateTo = null;
}

let query = `
  SELECT sd.id, sd.time, sd.value,
         COALESCE(a.type, 'No Alert') AS alert_type,
         COALESCE(a.pulses, 0) AS pulses,
         COALESCE(a.intensity, 0) AS intensity,
         COALESCE(a.duration, 0) AS duration,
         COALESCE(a.interval, 0) AS interval,
         sd.userid,
         sd.sensorid,
         a.vibration_reason AS reason
  FROM public."SensorData" sd
  LEFT JOIN public."Alert" a ON sd.alertid = a.alertid
`;

let where = [];
let params = [];
let p = 1;

// time filter - start date
if (dateFrom) {
  where.push(`sd.time >= $${p++}`);
  params.push(dateFrom.toISOString());
}

// time filter - end date (for custom range)
if (dateTo) {
  where.push(`sd.time <= $${p++}`);
  params.push(dateTo.toISOString());
}

// user filter
where.push(`sd.userid = $${p++}`);
params.push(userId);

// alert filter: by type OR by sensorid
if (isNumericAlertType) {
  where.push(`sd.sensorid = $${p++}`);
  params.push(Number(alertTypeStr));
} else {
  where.push(`a.type = $${p++}`);
  params.push(alertTypeStr);
}

query += ` WHERE ${where.join(" AND ")} ORDER BY sd.time;`;

return [{
  json: {
    statusCode: 200,
    query,
    params,
    meta: { range, alertTypeRaw: alertTypeStr, interpretedAs: isNumericAlertType ? "sensorid" : "type", dateFrom, dateTo }
  }
}];

const globalData = $getWorkflowStaticData('global');

