    }
  }
];

// 1. Get the raw text from the AI Agent
const rawOutput = $json.output || "";

// 2. Use a Regular Expression to find the first '{' and the last '}'
// This ignores any "Okay, sure!" text outside the brackets
const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  // If no JSON is found, return the message as "NONE" so the flow doesn't crash
  return [{ 
    json: { 
      message: rawOutput, 
      db_action: "NONE", 
      payload: null 
    } 
  }];
}

try {
  // 3. Parse only the part inside the curly braces
  const parsedData = JSON.parse(jsonMatch[0]);
  return [{ json: parsedData }];
} catch (e) {
  // 4. Fallback if the AI generates broken JSON
  return [{ 
    json: { 
      message: "The AI generated a malformed response. Raw: " + rawOutput, 
      db_action: "NONE", 
      payload: null 
    } 
  }];
}

