// Access global workflow memory
const staticData = $getWorkflowStaticData('global');

// Get current sensor data
const currentHR = parseFloat($('Webhook heart rate').item.json.body.Value); 
const currentTime = new Date().getTime();

let trendTrigger = false;

// Initialize snapshot if it doesn't exist yet
if (staticData.snapshotHR == null) {
    staticData.snapshotHR = currentHR;
    staticData.snapshotTime = currentTime;
}

// Calculate time since last snapshot
const timeDiff = currentTime - staticData.snapshotTime;

// Check if 0.5 minutes have passed
if (timeDiff >= 30000) {
    // 1. Compare Current vs Snapshot
    const pastHR = parseFloat(staticData.snapshotHR);

    // Check for 15 BPM difference (Absolute value handles up or down)
    if (Math.abs(currentHR - pastHR) >= 15) {
        trendTrigger = true;
    }

    // 2. UPDATE the snapshot for the next minute comparison
    // We update this regardless of whether we triggered or not
    staticData.snapshotHR = currentHR;
    staticData.snapshotTime = currentTime;
}

const diff = staticData.snapshotHR == null ? 0 : Math.abs(currentHR - staticData.snapshotHR);

return [{
  json: {
    ...items[0].json,
    trendTrigger,
    debug_timeDiffMs: timeDiff,
    debug_diff: diff,
    debug_snapshotHR: staticData.snapshotHR,
    debug_currentHR: currentHR
  }
}];

// 1. Get raw AI output
const rawOutput = $json.output || "";

// 2. Parse JSON (existing logic)
const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
let parsedData;

if (!jsonMatch) {
  parsedData = { 
    message: rawOutput, 
    db_action: "NONE", 
    payload: null 
  };
} else {
  try {
    parsedData = JSON.parse(jsonMatch[0]);
  } catch (e) {
    parsedData = { 
      message: "AI response error: " + rawOutput, 
      db_action: "NONE", 
      payload: null 
    };
  }
}

// 3. BULLETPROOF CHANNEL - Direct from Trigger
parsedData.channel = $input.first().json.event?.channel || 
                     $('Slack Trigger').all()[0]?.json.event?.channel || 
                     "C0ACXKM7QJJ";

return [{ json: parsedData }];

