CREATE OR REPLACE FUNCTION public.insert_sensor_data(
    _userid integer, 
    _watchid integer, 
    _phoneid integer, 
    _sensorname character varying, 
    _alertgiven character varying, 
    _value double precision, 
    _pulses integer, 
    _intensity integer, 
    _duration integer, 
    _interval integer, 
    _fbrangeid integer,
    _vibration_reason character varying DEFAULT NULL
) 
RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    _sensorID INT;
    _alertID INT;
    _assigned_usecase VARCHAR;
BEGIN
    SELECT uc.name INTO _assigned_usecase
    FROM public."User" u
    JOIN public."UseCase" uc ON u.active_usecase_id = uc.usecase_id
    WHERE u.userid = _userid;

    IF _assigned_usecase IS NULL OR _assigned_usecase != _sensorname THEN
        RAISE NOTICE 'Rejected data for User %: Expected %, received %', _userid, _assigned_usecase, _sensorname;
        RETURN; 
    END IF;

    INSERT INTO "User"(userID) SELECT _userID WHERE NOT EXISTS (SELECT 1 FROM "User" WHERE userID = _userID);
    INSERT INTO "Watch"(watchID) SELECT _watchID WHERE NOT EXISTS (SELECT 1 FROM "Watch" WHERE watchID = _watchID);
    INSERT INTO "AndroidPhone"(phoneID) SELECT _phoneID WHERE NOT EXISTS (SELECT 1 FROM "AndroidPhone" WHERE phoneID = _phoneID);

    INSERT INTO "WatchAndroidPhone"(watchID, phoneID)
    SELECT _watchID, _phoneID
    WHERE NOT EXISTS (
        SELECT 1 FROM "WatchAndroidPhone" WHERE watchID = _watchID AND phoneID = _phoneID
    );

    INSERT INTO "UserWatchAndroidPhone"(userID, watchID, phoneID)
    SELECT _userID, _watchID, _phoneID
    WHERE NOT EXISTS (
        SELECT 1 FROM "UserWatchAndroidPhone"
        WHERE userID = _userID AND watchID = _watchID AND phoneID = _phoneID
    );

    INSERT INTO "SensorType"(name)
    SELECT _sensorName
    WHERE NOT EXISTS (SELECT 1 FROM "SensorType" WHERE name = _sensorName);

    SELECT sensorID INTO _sensorID FROM "SensorType" WHERE name = _sensorName;

    INSERT INTO "Alert"(
        alertGiven, pulses, intensity, duration, interval, type, fbRangeID, vibration_reason
    )
    VALUES (
        _alertGiven, _pulses, _intensity, _duration, _interval, _sensorName, _fbrangeid, _vibration_reason
    )
    RETURNING alertID INTO _alertID;

    INSERT INTO "DeviceSensor"(sensorID, userID, watchID, phoneID)
    SELECT _sensorID, _userID, _watchID, _phoneID
    WHERE NOT EXISTS (
        SELECT 1 FROM "DeviceSensor"
        WHERE sensorID = _sensorID AND userID = _userID AND watchID = _watchID AND phoneID = _phoneID
    );

    INSERT INTO "SensorData"(sensorID, userID, watchID, phoneID, alertID, value, time)
    VALUES (_sensorID, _userID, _watchID, _phoneID, _alertID, _value, CURRENT_TIMESTAMP);

END;
$$;

