// This node receives output from the "AI Slack Router" agent node.
// That agent often returns its final text in $json.output (not $json.text).

function firstStringValue(obj) {
  if (!obj || typeof obj !== 'object') return undefined;
  for (const [k, v] of Object.entries(obj)) {
    if (typeof v === 'string' && v.trim()) return v;
  }
  return undefined;
}

const rawText =
  $json.output ??
  $json.text ??
  $json.response ??
  $json.result ??
  $json.message ??
  firstStringValue($json);

let parsed;

// Try to extract a JSON object from the text (even if the model added extra words)
const jsonCandidate = typeof rawText === 'string'
  ? (rawText.match(/\{[\s\S]*\}/)?.[0] ?? rawText)
  : rawText;

try {
  parsed = typeof jsonCandidate === "string" ? JSON.parse(jsonCandidate) : jsonCandidate;
} catch (e) {
  parsed = {
    intent: "knowledge",
    args: { question: ($node["ask: extract prompt"].json.aiPrompt || "") },
  };
}

// IMPORTANT: keep the original Slack fields (responseUrl etc.) from ask: extract prompt
return [{
  json: {
    ...$node["ask: extract prompt"].json,
    ai: parsed,
    _debug_rawText: rawText,       // keep for debugging; you can delete later
  }
}];

const range = $json.ai?.args?.range || "7d"; // default
const now = new Date();

let start;
let end = now;

if (range === "24h") {
  start = new Date(now.getTime() - 24 * 60 * 60 * 1000);
} else if (range === "7d") {
  start = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
} else if (range === "30d") {
  start = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
} else if (range === "custom") {
  start = new Date($json.ai.args.start);
  end = new Date($json.ai.args.end);
} else {
  // fallback
  start = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
}


const sensor_type = $json.current_usecase || "HeartRate";

const user_id = $json.user_id || 101;

return [{
  json: {
    ...$json,
    charts: {
      range,
      user_id,
      sensor_type,
      startISO: start.toISOString(),
      endISO: end.toISOString(),
    }
  }
}];

const userId = $json.charts?.user_id || 101;
const sensorType = $json.charts?.sensor_type || "HeartRate";
const range = $json.charts?.range || "7d";

// IMPORTANT: replace with your public base (ngrok) later.
// For local testing with Slack, you must use your ngrok URL.
const base = "https://marcella-unguerdoned-ayanna.ngrok-free.dev";

const viewUrl =
  `${base}/webhook/chart/view?user_id=${encodeURIComponent(userId)}` +
  `&sensor_type=${encodeURIComponent(sensorType)}` +
  `&range=${encodeURIComponent(range)}`;

return [{ json: { ...$json, viewUrl } }];

const q = $json.query || {};

const range = String(q.range || "7d");
const user_id = Number(q.user_id);
const sensor_type = String(q.sensor_type || "HeartRate");

if (!user_id || Number.isNaN(user_id)) {
  return [{ json: { error: "Missing/invalid user_id" } }];
}

const now = new Date();
let start = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
let end = now;

if (range === "24h") start = new Date(now.getTime() - 24 * 60 * 60 * 1000);
if (range === "30d") start = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);


return [{
  json: {
