    startISO: start.toISOString(),
    endISO: end.toISOString(),
  }
}];

const ctx = $items("compute time filter")[0].json;
const rows = $items("charts: fetch readings").map(i => i.json);

return [{
  json: {
    ...ctx,
    readings: rows
  }
}];

