=<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1"/>
  <title>Sensor Feedback Over Time</title>
  <script src="https://d3js.org/d3.v7.min.js"></script>
  <style>
    body { font-family: system-ui, Arial; margin: 0; padding: 20px; background:#0b1220; color:#e7eefc; }
    h2 { text-align:center; margin: 0 0 8px; }
    #meta-info, #data-stats { text-align:center; margin: 4px 0; color:#9bb0d1; }
    .wrap { max-width: 1100px; margin: 0 auto; }
    .panel { background: rgba(15,26,46,.55); border:1px solid rgba(255,255,255,.08); border-radius: 16px; padding: 14px; }
    svg { width: 100%; height: 650px; display:block; }
    .axis path, .axis line { stroke: rgba(255,255,255,.35); stroke-width: 1.2px; }
    .axis text { fill: #9bb0d1; font-size: 12px; }
    .grid line { stroke: rgba(255,255,255,.08); }
    .tooltip {
      position: absolute;
      background: rgba(15,26,46,.96);
      border: 1px solid rgba(255,255,255,.12);
      border-radius: 12px;
      padding: 10px 12px;
      box-shadow: 0 12px 30px rgba(0,0,0,.35);
      font-size: 12px;
      line-height: 1.35;
      pointer-events: none;
      opacity: 0;
      transform: translateY(-8px);
      transition: opacity .15s ease, transform .15s ease;
      color: #e7eefc;
    }
  </style>
</head>
<body>
  <div class="wrap">
    <div class="panel">
      <h2>Sensor Feedback Over Time</h2>
      <div id="meta-info"></div>
      <div id="data-stats"></div>
    </div>

    <div class="panel" style="margin-top:14px;">
      <svg></svg>
    </div>
  </div>

  <div class="tooltip"></div>

    <script>
  const params = new URLSearchParams(location.search);
  const userId = params.get("user_id") || "unknown";
  const sensorType = params.get("sensor_type") || "HeartRate";
  const range = params.get("range") || "7d";

  document.getElementById("meta-info").textContent =
    `User ID: ${userId} | Sensor: ${sensorType} | Range: ${range}`;

  const tooltip = d3.select(".tooltip");
  const svg = d3.select("svg");
  const margin = { top: 40, right: 40, bottom: 90, left: 80 };

  function showError(msg) {
    svg.selectAll("*").remove();
    svg.append("text")
      .attr("x", 30).attr("y", 60)
      .attr("fill", "#ffb4b4")
      .style("font-size", "14px")
      .text(msg);
  }

const base = `${location.protocol}//${location.host}`;
const dataUrl = `${base}/webhook/chart/data?user_id=${encodeURIComponent(userId)}&sensor_type=${encodeURIComponent(sensorType)}&range=${encodeURIComponent(range)}`;
document.getElementById("data-stats").textContent = `Loading from: ${dataUrl}`;


  // Temporary debug line
  document.getElementById("data-stats").textContent = `Loading from: ${dataUrl}`;

  fetch(dataUrl, {
  headers: { "ngrok-skip-browser-warning": "1" }
})
    .then(async (r) => {
      const text = await r.text();
      if (!r.ok) throw new Error(`HTTP ${r.status}: ${text.slice(0, 200)}`);
      try { return JSON.parse(text); }
      catch { throw new Error(`Response was not JSON. First 200 chars: ${text.slice(0, 200)}`); }
    })
    .then(data => {
      if (!Array.isArray(data) || data.length === 0) {
        showError("No data returned for this range/usecase.");
        document.getElementById("data-stats").textContent = "0 data points";
        return;
      }

      // ---- RENDER ----
      data.forEach(d => d.parsedTime = new Date(d.time));

      const width = svg.node().clientWidth - margin.left - margin.right;
      const height = svg.node().clientHeight - margin.top - margin.bottom;

      svg.selectAll("*").remove();

      svg.append("defs").append("clipPath")
        .attr("id","clip")
        .append("rect")
        .attr("x",0).attr("y",0)
        .attr("width",width).attr("height",height);

      const g = svg.append("g").attr("transform", `translate(${margin.left},${margin.top})`);
      const dataLayer = g.append("g").attr("clip-path","url(#clip)");

      const x = d3.scaleTime()
        .domain(d3.extent(data, d => d.parsedTime))
        .range([0, width]);

      const y = d3.scaleLinear()
        .domain([d3.min(data, d => d.value) - 5, d3.max(data, d => d.value) + 5])
        .nice()
        .range([height, 0]);

      const tickCount = Math.max(4, Math.min(10, Math.floor(width / 120)));

      const xAxisG = g.append("g")
        .attr("class","axis x-axis")
        .attr("transform", `translate(0,${height})`)
        .call(d3.axisBottom(x).ticks(tickCount));

      xAxisG.selectAll("text")
        .attr("transform","rotate(-35)")
        .style("text-anchor","end")
        .attr("dx","-0.6em")
        .attr("dy","0.2em");

      g.append("g")
        .attr("class","axis y-axis grid")
        .call(d3.axisLeft(y).ticks(6).tickSize(-width));

      const line = d3.line()
        .x(d => x(d.parsedTime))
        .y(d => y(d.value))
        .curve(d3.curveMonotoneX);

      const linePath = dataLayer.append("path")
        .datum(data)
        .attr("fill","none")
        .attr("stroke","#6aa6ff")
        .attr("stroke-width",2.2)
        .attr("d", line);

      const timeRange = d3.extent(data, d => d.parsedTime);
      document.getElementById("data-stats").textContent =
        `${data.length} data points | Range: ${timeRange[0].toISOString()} → ${timeRange[1].toISOString()}`;

      // hover (nearest-ish)
      const overlay = dataLayer.append("rect")
        .attr("width", width)
        .attr("height", height)
        .attr("fill", "transparent");

      overlay.on("mousemove", (event) => {
        const [mx] = d3.pointer(event);
        const xm = x.invert(mx);
        const bisect = d3.bisector(d => d.parsedTime).left;
        const i = bisect(data, xm);
        const d = data[Math.min(data.length - 1, Math.max(0, i))];

        tooltip
          .style("left", (event.pageX + 12) + "px")
          .style("top", (event.pageY - 12) + "px")
          .style("opacity", 1)
          .style("transform", "translateY(0)")
          .html(`<strong>${d.parsedTime.toISOString()}</strong><br/>Value: ${d.value}`);
      });

      overlay.on("mouseleave", () => tooltip.style("opacity", 0));

      // zoom
      const zoom = d3.zoom()
        .scaleExtent([1, 80])
        .translateExtent([[-width, 0], [2*width, height]])
        .extent([[0,0],[width,height]])
        .on("zoom", (event) => {
          const zx = event.transform.rescaleX(x);

          xAxisG.call(d3.axisBottom(zx).ticks(Math.max(4, Math.min(12, Math.floor(width/100)))));
          xAxisG.selectAll("text")
            .attr("transform","rotate(-35)")
            .style("text-anchor","end")
            .attr("dx","-0.6em")
            .attr("dy","0.2em");

          const zLine = d3.line()
            .x(d => zx(d.parsedTime))
            .y(d => y(d.value))
            .curve(d3.curveMonotoneX);

          linePath.attr("d", zLine);
        });

      svg.call(zoom).on("dblclick.zoom", null);
    })
    .catch((err) => showError(`Failed to load chart data: ${err.message}`));
</script>
</body>
</html>

