const body = $json.body;
const event = body.event || {};

// Ignore bot's own messages to prevent loops
if (event.bot_id) return [];

// Strip the @mention prefix if present (e.g. "<@U12345> show me charts")
const rawText = (event.text || "").trim();
const cleanText = rawText.replace(/<@[A-Z0-9]+>/g, "").trim();

return [{
  json: {
    slackUserId: event.user,
    channelId: event.channel,
    commandText: cleanText,
    verb: "ask",        // treat everything as "ask" - no more slash verbs
    args: cleanText,
    responseUrl: null,  // Events API doesn't have responseUrl, use chat.postMessage instead
    teamId: body.team_id || "",
  }
}];

const responseUrl = $json.responseUrl;
const channelId = $json.channelId;
const message = $json.message ?? "No mappings found.";

const text = `🧩 *Active mappings (${$json.count}):*\n\`\`\`${$json.message}\`\`\``;

let body;
if (responseUrl) {
  body = { response_type: "ephemeral", text };
} else {
  body = { channel: channelId, text };
}


return [{ json: { ...$json, slackBody: JSON.stringify(body) } }];

const responseUrl = $json.responseUrl;
const channelId = $json.channelId;

const text = "💬 Just ask me anything! Try: _show me my heart rate chart for the last 7 days_";

let body;

if (responseUrl) {
  body = {
    response_type: "ephemeral",
    text
  };
} else {
  body = {
    channel: channelId,
    text
  };
}

return [{ json: { ...$json, slackBody: JSON.stringify(body) } }];

const responseUrl = $json.responseUrl;
const channelId = $json.channelId;
const viewUrl = $json.viewUrl;

const blocks = [
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: `📊 *Interactive chart ready*\n<${viewUrl}|Open chart in browser>`
    }
  },
  {
    type: "actions",
    elements: [
      {
        type: "button",
        text: { type: "plain_text", text: "Open chart" },
        url: viewUrl,
        action_id: "open_chart"
      }
    ]
  }
];

let body;

if (responseUrl) {
  body = {
    response_type: "ephemeral",
    text: `📊 Interactive chart: ${viewUrl}`,
    blocks
  };
} else {
  body = {
    channel: channelId,
    text: `📊 Interactive chart: ${viewUrl}`,
    blocks
  };
}

return [{ json: { ...$json, slackBody: JSON.stringify(body) } }];

const aiType = $json.ai?.args?.type || "";
const current = $json.current_usecase || "";

return [{ 
  json: { 
    ...$json, 
    args: aiType,
    typeFilter: aiType || current 
  } 
}];

const question = $json.ai?.args?.question || $json.aiPrompt || "";
const currentUsecase = $json.current_usecase || "HeartRate";

const prompt = `You are an expert assistant on haptic feedback and sensory substitution research.
The user is working with a smartwatch haptic feedback system that maps sensor data (heart rate, sun azimuth, moon azimuth, pollution) to vibration patterns.
Their current active use case is: ${currentUsecase}

Answer the following question clearly and concisely. Use plain text only, no markdown headers.
Keep your answer under 200 words.

Question: ${question}`;

return [{ json: { ...$json, knowledgePrompt: prompt } }];

const answer = $json.text || $json.output || $json.response || "I couldn't find an answer to that.";

// LLM chain drops context, so pull Slack fields from upstream node
const channelId = $node["knowledge: build prompt"].json.channelId;
const responseUrl = $node["knowledge: build prompt"].json.responseUrl;
const slackUserId = $node["knowledge: build prompt"].json.slackUserId;
const aiPrompt = $node["knowledge: build prompt"].json.aiPrompt;
const ai = $node["knowledge: build prompt"].json.ai;

let body;

if (responseUrl) {
  body = {
    response_type: "ephemeral",
    text: `💡 ${answer}`
  };
} else {
  body = {
    channel: channelId,
    text: `💡 ${answer}`
  };
}

return [{ json: { channelId, responseUrl, slackUserId, aiPrompt, ai, slackBody: JSON.stringify(body) } }];

// LLM drops context so pull it back from upstream
const upstream = $node["experiment: build prompt"].json;

let sql = ($json.text || $json.output || $json.response || "").trim();

// Strip any markdown code fences the model might have added anyway
sql = sql.replace(/```sql/gi, "").replace(/```/g, "").trim();

// Safety check - block any non-SELECT queries
if (!sql.toLowerCase().startsWith("select")) {
  return [{ 
    json: { 
      ...upstream,
      sqlError: "Generated query was not a SELECT statement.",
      sql: null
    } 
  }];
}

return [{ json: { ...upstream, sql } }];

const upstream = $node["experiment: extract SQL"].json;
const rows = $input.all().map(i => i.json);
const question = upstream.ai?.args?.question || upstream.aiPrompt || "";

const resultText = rows.length === 0 
  ? "No results found."
  : JSON.stringify(rows.slice(0, 20), null, 2);

const prompt = `The user asked: "${question}"

A SQL query was run and returned these results:
${resultText}

Summarize the results in 2-4 plain sentences. Be specific about numbers and dates. No markdown.`;

return [{ json: { ...upstream, summaryPrompt: prompt } }];

const upstream = $node["experiment: build summary prompt"].json;
const answer = $json.text || $json.output || $json.response || "I couldn't summarize the results.";

const channelId = upstream.channelId;
const responseUrl = upstream.responseUrl;
const slackUserId = upstream.slackUserId;
const aiPrompt = upstream.aiPrompt;
const ai = upstream.ai;

let body;

if (responseUrl) {
  body = { response_type: "ephemeral", text: `📊 ${answer}` };
} else {
  body = { channel: channelId, text: `📊 ${answer}` };
}

return [{ json: { channelId, responseUrl, slackUserId, aiPrompt, ai, slackBody: JSON.stringify(body) } }];

const channelId = $json.channelId;
const responseUrl = $json.responseUrl;

let body;
if (responseUrl) {
  body = { response_type: "ephemeral", text: "⚠️ I couldn't generate a valid query for that question. Try rephrasing it." };
} else {
  body = { channel: channelId, text: "⚠️ I couldn't generate a valid query for that question. Try rephrasing it." };
}

return [{ json: { ...$json, slackBody: JSON.stringify(body) } }];

const intent = $json.ai?.intent ?? "unknown";
const userMessage = $json.aiPrompt ?? "";
const isOffTopic = intent === "off_topic";

const systemContext = `You are a helpful Slack bot assistant for a Smartwatch Haptic Feedback system. 
The system supports: viewing sensor charts, listing/managing haptic mappings, answering knowledge questions about haptic feedback, and running data experiments.
Available usecases: HeartRate, SunAzimuth, MoonAzimuth, Pollution.`;

const prompt = isOffTopic
  ? `${systemContext}

The user sent a message unrelated to the system: "${userMessage}"

Respond in 2-3 sentences. Politely let them know what you can help with and give one relevant example. Be friendly and concise. Plain text only, no markdown.`
  : `${systemContext}

The user asked: "${userMessage}"
The detected intent was: "${intent}" — which is not yet supported.

Respond in 2-3 sentences. Acknowledge what they're trying to do, explain it's not supported yet, and suggest something related you can help with instead. Plain text only, no markdown.`;

const channelId = $json.channelId;
const responseUrl = $json.responseUrl;
const slackUserId = $json.slackUserId;

return [{ json: { ...$json, fallbackPrompt: prompt, channelId, responseUrl, slackUserId } }];

const answer = $json.text || $json.output || $json.response || "I'm not sure how to help with that. Try asking about charts, mappings, or haptic feedback.";

const upstream = $node["build unhandled intent prompt"].json;
const channelId = upstream.channelId;
const responseUrl = upstream.responseUrl;
const slackUserId = upstream.slackUserId;
const aiPrompt = upstream.aiPrompt;
const ai = upstream.ai;

let body;
if (responseUrl) {
  body = { response_type: "ephemeral", text: answer };
} else {
  body = { channel: channelId, text: answer };
}

return [{ json: { channelId, responseUrl, slackUserId, aiPrompt, ai, slackBody: JSON.stringify(body) } }];
